import { http } from "./http";

export const createOrder = async (orderData) => {
  try {
    const response = await http.post("orders", orderData);
    return response.data;
  } catch (error) {
    console.error("Error creating order:", error);
    throw error;
  }
};

export const getMyOrders = async (userId, page = 1, limit = 10) => {
  try {
    if (!userId) {
      throw new Error("User ID is required to fetch orders");
    }
    const response = await http.get(`orders/user/${userId}`, {
      params: { page, limit },
    });
    return response.data;
  } catch (error) {
    console.error(error);
    throw error;
  }
};

export const getOrderById = async (orderId) => {
  try {
    const response = await http.get(`orders/${orderId}`);
    return response.data;
  } catch (error) {
    console.error(error);
    throw error;
  }
};

export const getAllOrders = async (page = 1, limit = 50) => {
  try {
    const response = await http.get(`orders`, {
      params: { page, limit },
    });
    return response.data;
  } catch (error) {
    console.error("Error fetching all orders:", error);
    throw error;
  }
};

export const updateOrderStatus = async (orderId, status) => {
  try {
    const response = await http.put(`orders/${orderId}/status`, { status });
    return response.data;
  } catch (error) {
    console.error("Error updating order status:", error);
    throw error;
  }
};
